    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // 2. Create the Product table with if_not_exists
    auto create_table_op = sqlgen::create_table<Product> | sqlgen::if_not_exists;
    auto create_table_result = create_table_op(conn);
    if (!create_table_result) {
      return false;
    }

    // 3. Create standard index on category with if_not_exists
    auto index_category_op = sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists;
    auto index_category_result = index_category_op(conn);
    if (!index_category_result) {
      return false;
    }

    // 4. Create unique index on sku with if_not_exists
    auto index_sku_op = sqlgen::create_index<"idx_product_sku", Product>("sku"_c) | sqlgen::if_not_exists;
    // Set unique flag (assuming CreateIndex has a unique_ member)
    index_sku_op.unique_ = true;
    auto index_sku_result = index_sku_op(conn);
    if (!index_sku_result) {
      return false;
    }

    // 5. Create composite index on name and price with if_not_exists
    auto index_composite_op = sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c) | sqlgen::if_not_exists;
    auto index_composite_result = index_composite_op(conn);
