bool migration_add_column() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Generate ALTER TABLE statements using to_create_table
  // Note: We're using the UserAfter structure which contains the new columns
  auto create_table_stmt = sqlgen::transpilation::to_create_table<UserAfter>(true);

  // 3. Convert the dynamic statement to SQL string
