  auto create_view_stmt = sqlgen::create_as<SalesSummary>(select_query) | sqlgen::if_not_exists;

  // 4. Convert to SQL and execute
  std::string sql = sqlgen::sqlite::to_sql(create_view_stmt);
  auto execute_result = conn->execute(sql);

  return execute_result;
}

}  // namespace schema_create_view_sales_summary
