JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create tables
  auto create_dept = sqlgen::create_table<Department>;
  auto create_emp = sqlgen::create_table<Employee>;

  // 3. Insert data
  auto insert_dept = sqlgen::insert(depts);
  auto insert_emp = sqlgen::insert(emps);

  // Execute operations on connection
  conn | create_dept;
  conn | create_emp;
  conn | insert_dept;
  conn | insert_emp;

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_d, "first_name"_e, "last_name"_e, "salary"_e)
      | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e);
  auto inner_results = sqlgen::read<std::vector<JoinResult>>(inner_query)(conn).value();

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_e, "last_name"_e, "salary"_e, "department_name"_d)
      | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d);
  auto left_results = sqlgen::read<std::vector<JoinResult>>(left_query)(conn).value();

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">("department_name"_d, "first_name"_e, "last_name"_e, "salary"_e)
      | sqlgen::right_join<Employee, "e">("department_id"_d == "department_id"_e);
  auto right_results = sqlgen::read<std::vector<JoinResult>>(right_query)(conn).value();

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">("department_name"_d, "first_name"_e, "last_name"_e, "salary"_e)
      | sqlgen::full_join<Employee, "e">("department_id"_d == "department_id"_e);
  auto full_results = sqlgen::read<std::vector<JoinResult>>(full_query)(conn).value();

  // 8. Build and return JoinAnalysis
  JoinAnalysis analysis;
  analysis.inner_join_results = inner_results;
  analysis.left_join_results = left_results;
  analysis.right_join_results = right_results;
  analysis.full_join_results = full_results;

  return analysis;
}

}  // namespace analyze_department_employees
```

