    auto combined_condition = age_condition || status_condition;

    // Apply where clause to delete_from using pipe operator
    auto delete_query = sqlgen::delete_from<User> | sqlgen::where(combined_condition);

    // Convert to SQL string
    return sqlgen::sqlite::to_sql(delete_query);
}

}  // namespace delete_with_complex_condition
```

