#include <vector>

namespace in_operator_usage {

struct Status {
  sqlgen::PrimaryKey<int> id;
  int code;
};

/**
 * This function demonstrates IN operator usage.
 * Returns: std::string.
 */
inline std::string in_operator_usage() {
  using namespace sqlgen::literals;

  // Create column reference for "code" using literal operator
  auto code_col = "code"_c;

  // Construct query using select_from, apply IN condition with where, and convert to SQL
  auto query = sqlgen::select_from<Status>(code_col) 
             | sqlgen::where(code_col.in(1, 2, 3));

