 * This function demonstrates COALESCE usage.
 * Returns: query value.
 */
inline auto coalesce_function() {
    using namespace sqlgen::literals;

    // Create the COALESCE expression: COALESCE(nickname, 'Anonymous')
    auto coalesce_expr = sqlgen::coalesce("nickname"_c, "Anonymous");

    // Alias the result as "display_name"
